"""
Online statistics computation using Welford's algorithm.

Supports streaming computation of mean and standard deviation.
"""

import numpy as np
from typing import Optional, Tuple
import json


class WelfordStats:
    """
    Online statistics calculator using Welford's algorithm.
    
    Efficiently computes mean and variance in a single pass.
    """
    
    def __init__(self, n_features: int):
        """
        Args:
            n_features: Number of features (dimensions)
        """
        self.n_features = n_features
        self.count = 0
        self.mean = np.zeros(n_features, dtype=np.float64)
        self.M2 = np.zeros(n_features, dtype=np.float64)  # Sum of squared differences
    
    def update(self, x: np.ndarray) -> None:
        """
        Update statistics with new sample(s).
        
        Args:
            x: (N, n_features) or (n_features,) array
        """
        x = np.asarray(x, dtype=np.float64)
        if x.ndim == 1:
            x = x[np.newaxis, :]
        
        for sample in x:
            self.count += 1
            delta = sample - self.mean
            self.mean += delta / self.count
            delta2 = sample - self.mean
            self.M2 += delta * delta2
    
    def get_mean(self) -> np.ndarray:
        """Get current mean."""
        return self.mean.copy()
    
    def get_std(self, std_floor: float = 1e-2) -> np.ndarray:
        """
        Get current standard deviation.
        
        Args:
            std_floor: Minimum std value (prevents division by zero)
            
        Returns:
            (n_features,) standard deviation array
        """
        if self.count < 2:
            return np.full(self.n_features, std_floor, dtype=np.float64)
        
        variance = self.M2 / (self.count - 1)
        std = np.sqrt(variance)
        std = np.maximum(std, std_floor)
        return std
    
    def get_stats(self, std_floor: float = 1e-2) -> Tuple[np.ndarray, np.ndarray]:
        """Get both mean and std."""
        return self.get_mean(), self.get_std(std_floor)


def compute_stats_from_array(data: np.ndarray, std_floor: float = 1e-2) -> Tuple[np.ndarray, np.ndarray]:
    """
    Compute mean and std from array (2-pass, for validation).
    
    Args:
        data: (N, n_features) array
        std_floor: Minimum std value
        
    Returns:
        (mean, std) tuple
    """
    mean = np.mean(data, axis=0)
    std = np.std(data, axis=0)
    std = np.maximum(std, std_floor)
    return mean, std


def save_norm_params(
    x_mean: np.ndarray,
    x_std: np.ndarray,
    y_mean: np.ndarray,
    y_std: np.ndarray,
    std_floor: float,
    filepath: str
) -> None:
    """
    Save normalization parameters to JSON.
    
    Args:
        x_mean: (18,) input mean
        x_std: (18,) input std
        y_mean: (8,) output mean
        y_std: (8,) output std
        std_floor: std_floor value used
        filepath: Output JSON file path
    """
    feature_order = [
        "sin_j1", "sin_j2", "sin_j3", "sin_j4", "sin_j5", "sin_j6",
        "cos_j1", "cos_j2", "cos_j3", "cos_j4", "cos_j5", "cos_j6",
        "jv1", "jv2", "jv3", "jv4", "jv5", "jv6"
    ]
    target_order = [f"raw{i}" for i in range(1, 9)]
    
    data = {
        "x_mean": x_mean.tolist(),
        "x_std": x_std.tolist(),
        "y_mean": y_mean.tolist(),
        "y_std": y_std.tolist(),
        "std_floor": std_floor,
        "feature_order": feature_order,
        "target_order": target_order,
    }
    
    with open(filepath, 'w') as f:
        json.dump(data, f, indent=2)


def load_norm_params(filepath: str) -> Tuple[np.ndarray, np.ndarray, np.ndarray, np.ndarray, float]:
    """
    Load normalization parameters from JSON.
    
    Returns:
        (x_mean, x_std, y_mean, y_std, std_floor) tuple
    """
    with open(filepath, 'r') as f:
        data = json.load(f)
    
    x_mean = np.array(data["x_mean"], dtype=np.float32)
    x_std = np.array(data["x_std"], dtype=np.float32)
    y_mean = np.array(data["y_mean"], dtype=np.float32)
    y_std = np.array(data["y_std"], dtype=np.float32)
    std_floor = float(data.get("std_floor", 1e-2))
    
    return x_mean, x_std, y_mean, y_std, std_floor


